import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';

// ─── Theme tokens ──────────────────────────────────────────────────────────────
const themes = {
  light: {
    pageBg:       '#f0f4f8',
    cardBg:       '#ffffff',
    text:         '#0d2137',
    textSub:      '#4a5568',
    textMuted:    '#8a9bb0',
    accent:       '#C17B2A',
    accentHover:  '#a86520',
    accentGlow:   'rgba(193,123,42,0.18)',
    accentLight:  '#fdf3e3',
    navy:         '#1a3c5e',
    border:       '#e8ecf0',
    borderFocus:  '#C17B2A',
    inputBg:      '#ffffff',
    inputBorder:  '#dde3eb',
    shadow:       '0 2px 12px rgba(0,0,0,0.07)',
    shadowCard:   '0 8px 40px rgba(0,0,0,0.10)',
    panelGrad:    'linear-gradient(160deg, #0a1f35 0%, #1a3c5e 45%, #1e5080 100%)',
    panelBlob1:   '#e67e22',
    panelBlob2:   '#1a5276',
    tagBg:        'rgba(193,123,42,0.18)',
    tagColor:     '#C17B2A',
    pillBg:       'rgba(255,255,255,0.09)',
    pillBorder:   'rgba(255,255,255,0.13)',
    statBg:       'rgba(255,255,255,0.07)',
    errorBg:      'rgba(231,76,60,0.07)',
    errorBorder:  'rgba(231,76,60,0.25)',
    infoBg:       '#fdf3e3',
    infoBorder:   'rgba(193,123,42,0.3)',
  },
  dark: {
    pageBg:       '#0c0e12',
    cardBg:       '#161b22',
    text:         '#e8edf3',
    textSub:      '#8b95a1',
    textMuted:    '#4a5568',
    accent:       '#e09640',
    accentHover:  '#c17b2a',
    accentGlow:   'rgba(224,150,64,0.22)',
    accentLight:  'rgba(224,150,64,0.1)',
    navy:         '#4a90d9',
    border:       'rgba(255,255,255,0.08)',
    borderFocus:  '#e09640',
    inputBg:      '#1e242e',
    inputBorder:  'rgba(255,255,255,0.1)',
    shadow:       '0 2px 12px rgba(0,0,0,0.4)',
    shadowCard:   '0 8px 40px rgba(0,0,0,0.5)',
    panelGrad:    'linear-gradient(160deg, #060a10 0%, #0d1a2e 45%, #0f2240 100%)',
    panelBlob1:   '#c17b2a',
    panelBlob2:   '#0a2240',
    tagBg:        'rgba(224,150,64,0.15)',
    tagColor:     '#e09640',
    pillBg:       'rgba(255,255,255,0.06)',
    pillBorder:   'rgba(255,255,255,0.09)',
    statBg:       'rgba(255,255,255,0.05)',
    errorBg:      'rgba(231,76,60,0.1)',
    errorBorder:  'rgba(231,76,60,0.3)',
    infoBg:       'rgba(224,150,64,0.08)',
    infoBorder:   'rgba(224,150,64,0.25)',
  },
};

const getInitialDark = () => {
  try {
    const s = localStorage.getItem('propmaintain_theme');
    if (s) return s === 'dark';
    return window.matchMedia('(prefers-color-scheme: dark)').matches;
  } catch { return false; }
};

// ─── Left-panel stats ──────────────────────────────────────────────────────────
const STATS = [
  { value: '2,400+', label: 'Verified Reviews'  },
  { value: '98%',    label: 'Job Success Rate'  },
  { value: '500+',   label: 'Pro Providers'     },
];

const FEATURES = [
  { icon: '⚡', label: 'Instant Matching',   desc: 'Get matched in under 60 seconds' },
  { icon: '🔒', label: 'Vetted Providers',   desc: 'Every pro is background-checked' },
  { icon: '📅', label: 'Smart Scheduling',   desc: 'Book at your convenience'        },
  { icon: '💬', label: 'Live Chat',          desc: 'Talk directly with your pro'     },
];

const AuthLayout = ({ children, title, subtitle }) => {
  const [dark, setDark] = useState(getInitialDark);
  const t = dark ? themes.dark : themes.light;

  useEffect(() => {
    localStorage.setItem('propmaintain_theme', dark ? 'dark' : 'light');
  }, [dark]);

  return (
    <div style={{ display: 'flex', minHeight: '100vh', fontFamily: "'Outfit', sans-serif", background: t.pageBg, transition: 'background 0.35s' }}>

      {/* ── Global styles ── */}
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Outfit:wght@300;400;500;600;700;800;900&family=Playfair+Display:ital,wght@0,700;0,800;1,700&display=swap');
        *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

        @keyframes fadeUp    { from{opacity:0;transform:translateY(18px);} to{opacity:1;transform:translateY(0);} }
        @keyframes float     { 0%,100%{transform:translateY(0);} 50%{transform:translateY(-12px);} }
        @keyframes rotateCW  { from{transform:rotate(0deg);} to{transform:rotate(360deg);} }
        @keyframes rotateCCW { from{transform:rotate(0deg);} to{transform:rotate(-360deg);} }
        @keyframes pulse     { 0%,100%{opacity:.5;transform:scale(1);} 50%{opacity:1;transform:scale(1.1);} }
        @keyframes shimmer   { 0%{background-position:-200% center;} 100%{background-position:200% center;} }

        /* ── Form inputs ── */
        .auth-form-input {
          width: 100%; padding: 12px 16px;
          border: 1.5px solid ${t.inputBorder};
          border-radius: 10px;
          font-size: 14px; font-family: 'Outfit', sans-serif;
          color: ${t.text}; background: ${t.inputBg};
          outline: none; box-sizing: border-box;
          transition: border-color 0.2s, box-shadow 0.2s, background 0.2s;
        }
        .auth-form-input:focus {
          border-color: ${t.borderFocus} !important;
          box-shadow: 0 0 0 3.5px ${t.accentGlow};
          background: ${t.inputBg};
        }
        .auth-form-input::placeholder { color: ${t.textMuted}; }

        /* ── Labels ── */
        .auth-form-label {
          font-size: 12.5px; font-weight: 700; color: ${t.text};
          display: block; margin-bottom: 6px;
          letter-spacing: 0.2px; font-family: 'Outfit', sans-serif;
          text-transform: uppercase;
        }
        .auth-form-error { margin:4px 0 0; font-size:12px; color:#e74c3c; font-family:'Outfit',sans-serif; }
        .auth-form-hint  { margin:4px 0 0; font-size:12px; color:${t.textMuted}; font-family:'Outfit',sans-serif; }

        /* ── Primary button ── */
        .auth-submit-btn {
          width: 100%; padding: 14px; border-radius: 10px;
          background: ${t.accent}; color: #fff; border: none;
          font-size: 15px; font-weight: 700; letter-spacing: 0.3px;
          font-family: 'Outfit', sans-serif; cursor: pointer;
          transition: transform 0.2s, box-shadow 0.2s, background 0.2s;
          margin-bottom: 16px;
          box-shadow: 0 4px 18px ${t.accentGlow};
        }
        .auth-submit-btn:hover:not(:disabled) { transform: translateY(-2px); box-shadow: 0 8px 26px ${t.accentGlow}; background: ${t.accentHover}; }
        .auth-submit-btn:active:not(:disabled) { transform: translateY(0); }
        .auth-submit-btn:disabled { background: ${t.textMuted}; cursor: not-allowed; transform: none; box-shadow: none; }

        /* ── Secondary button ── */
        .auth-secondary-btn {
          display: block; width: 100%; padding: 13px;
          border: 2px solid ${t.border}; border-radius: 10px;
          text-align: center; font-size: 14px; font-weight: 600;
          font-family: 'Outfit', sans-serif; color: ${t.text};
          text-decoration: none; background: transparent;
          box-sizing: border-box; transition: all 0.2s;
        }
        .auth-secondary-btn:hover { border-color: ${t.accent}; color: ${t.accent}; background: ${t.accentLight}; }

        /* ── Error / info boxes ── */
        .auth-error-box {
          background: ${t.errorBg}; border: 1px solid ${t.errorBorder};
          border-radius: 10px; padding: 12px 15px; font-size: 13px;
          color: #e74c3c; margin-bottom: 16px; font-family: 'Outfit', sans-serif;
          animation: fadeUp 0.25s ease both;
        }
        .auth-info-box {
          background: ${t.infoBg}; border: 1px solid ${t.infoBorder};
          border-radius: 10px; padding: 12px 15px; font-size: 13px;
          color: ${t.accent}; margin-bottom: 16px; font-family: 'Outfit', sans-serif;
        }

        /* ── Link ── */
        .auth-link { color: ${t.accent}; font-weight: 600; text-decoration: none; transition: color 0.2s; }
        .auth-link:hover { color: ${t.accentHover}; text-decoration: underline; }

        /* ── Divider ── */
        .auth-divider { display:flex; align-items:center; gap:12px; margin:10px 0 16px; }
        .auth-divider-line { flex:1; height:1px; background:${t.border}; }
        .auth-divider-text { font-size:12px; color:${t.textMuted}; white-space:nowrap; font-family:'Outfit',sans-serif; }

        /* ── Checkbox ── */
        .auth-checkbox { accent-color:${t.accent}; cursor:pointer; width:15px; height:15px; }

        /* ── Role cards ── */
        .role-card {
          display:flex; flex-direction:column; gap:5px; padding:16px 14px;
          border:2px solid ${t.border}; border-radius:12px; cursor:pointer;
          transition:all 0.2s; background:${t.cardBg};
        }
        .role-card:hover { border-color:${t.accent}; box-shadow:0 0 0 3px ${t.accentGlow}; }
        .role-card-active { border-color:${t.accent} !important; background:${t.accentLight} !important; box-shadow:0 0 0 3px ${t.accentGlow} !important; }
        .role-label { font-size:13.5px; font-weight:700; color:${t.text}; font-family:'Outfit',sans-serif; }
        .role-sub   { font-size:11px; color:${t.textMuted}; font-family:'Outfit',sans-serif; }

        /* ── Theme toggle ── */
        .theme-toggle { transition: transform 0.3s, box-shadow 0.2s; }
        .theme-toggle:hover { transform: rotate(20deg) scale(1.15); }
      `}</style>

      {/* ═══════════════════════════════════════════════
          LEFT PANEL
      ═══════════════════════════════════════════════ */}
      <div style={{
        flex: '0 0 42%', position: 'relative', overflow: 'hidden',
        background: t.panelGrad,
        display: 'flex', flexDirection: 'column', justifyContent: 'space-between',
        padding: '44px 48px',
      }}>

        {/* ── Decorative rings ── */}
        <div style={{ position:'absolute', top:'-80px', right:'-80px', width:'420px', height:'420px', borderRadius:'50%', border:'1px solid rgba(255,255,255,0.05)', animation:'rotateCW 40s linear infinite', pointerEvents:'none' }} />
        <div style={{ position:'absolute', top:'-20px', right:'-20px', width:'280px', height:'280px', borderRadius:'50%', border:'1px dashed rgba(193,123,42,0.2)', animation:'rotateCCW 25s linear infinite', pointerEvents:'none' }} />
        <div style={{ position:'absolute', bottom:'-100px', left:'-60px', width:'360px', height:'360px', borderRadius:'50%', border:'1px solid rgba(255,255,255,0.04)', animation:'rotateCW 35s linear infinite', pointerEvents:'none' }} />

        {/* ── Blob glows ── */}
        <div style={{ position:'absolute', top:'-40px', right:'-40px', width:'340px', height:'340px', borderRadius:'50%', background:t.panelBlob1, filter:'blur(100px)', opacity:0.14, pointerEvents:'none' }} />
        <div style={{ position:'absolute', bottom:'-20px', left:'-20px', width:'280px', height:'280px', borderRadius:'50%', background:t.panelBlob2, filter:'blur(80px)', opacity:0.2, pointerEvents:'none' }} />
        <div style={{ position:'absolute', top:'45%', left:'38%', width:'100px', height:'100px', borderRadius:'50%', background:'rgba(193,123,42,0.15)', filter:'blur(40px)', animation:'float 7s ease-in-out infinite', pointerEvents:'none' }} />

        {/* ── Top: Logo ── */}
        <div style={{ position:'relative', zIndex:2 }}>
          <Link to="/home" style={{ display:'inline-flex', alignItems:'center', gap:'10px', textDecoration:'none' }}>
            <div style={{ width:'42px', height:'42px', background:'linear-gradient(135deg, #C17B2A, #1a3c5e)', borderRadius:'12px', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'20px', boxShadow:'0 4px 16px rgba(193,123,42,0.3)' }}>🏠</div>
            <span style={{ fontSize:'22px', fontWeight:'800', color:'#fff', letterSpacing:'-0.4px' }}>
              Prop<span style={{ color:'#C17B2A' }}>Maintain</span>
            </span>
          </Link>
        </div>

        {/* ── Middle: Hero text + features ── */}
        <div style={{ position:'relative', zIndex:2, flex:1, display:'flex', flexDirection:'column', justifyContent:'center', paddingTop:'32px', paddingBottom:'32px' }}>

          {/* Badge */}
          <div style={{ display:'inline-flex', alignItems:'center', gap:'7px', padding:'5px 13px', borderRadius:'20px', background:'rgba(193,123,42,0.2)', border:'1px solid rgba(193,123,42,0.35)', width:'fit-content', marginBottom:'22px', animation:'fadeUp 0.6s ease both' }}>
            <span style={{ width:'6px', height:'6px', borderRadius:'50%', background:'#C17B2A', animation:'pulse 2s infinite', display:'inline-block' }} />
            <span style={{ fontSize:'11px', fontWeight:'700', color:'#C17B2A', letterSpacing:'1px', textTransform:'uppercase' }}>Now Live in the UK</span>
          </div>

          {/* Heading */}
          <h2 style={{ fontFamily:"'Playfair Display', serif", fontSize:'38px', fontWeight:'800', color:'#ffffff', lineHeight:1.12, letterSpacing:'-0.5px', marginBottom:'16px', animation:'fadeUp 0.6s ease 0.05s both' }}>
            Your Home,<br />
            <em style={{ color:'#C17B2A', fontStyle:'italic' }}>Perfectly</em><br />
            Maintained.
          </h2>

          <p style={{ fontSize:'14px', color:'rgba(255,255,255,0.6)', lineHeight:1.75, maxWidth:'300px', marginBottom:'36px', animation:'fadeUp 0.6s ease 0.1s both' }}>
            On-demand property maintenance — connecting homeowners with verified professionals instantly or on schedule.
          </p>

          {/* Feature rows */}
          <div style={{ display:'flex', flexDirection:'column', gap:'10px', marginBottom:'0', animation:'fadeUp 0.6s ease 0.15s both' }}>
            {FEATURES.map(({ icon, label, desc }, i) => (
              <div key={label} style={{
                display:'flex', alignItems:'center', gap:'14px',
                background:'rgba(255,255,255,0.07)', border:'1px solid rgba(255,255,255,0.1)',
                backdropFilter:'blur(6px)', borderRadius:'12px', padding:'12px 16px',
                transition:'background 0.2s',
              }}>
                <div style={{ width:'36px', height:'36px', borderRadius:'10px', background:'rgba(193,123,42,0.2)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'16px', flexShrink:0 }}>
                  {icon}
                </div>
                <div>
                  <p style={{ fontSize:'13px', fontWeight:'700', color:'#fff', margin:'0 0 2px' }}>{label}</p>
                  <p style={{ fontSize:'11px', color:'rgba(255,255,255,0.5)', margin:0 }}>{desc}</p>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* ── Bottom: Stats + avatars ── */}
        <div style={{ position:'relative', zIndex:2 }}>
          {/* Stats */}
          <div style={{ display:'flex', gap:'8px', marginBottom:'20px' }}>
            {STATS.map(({ value, label }) => (
              <div key={label} style={{ flex:1, background:'rgba(255,255,255,0.07)', border:'1px solid rgba(255,255,255,0.1)', borderRadius:'10px', padding:'12px 10px', textAlign:'center' }}>
                <p style={{ fontSize:'18px', fontWeight:'800', color:'#C17B2A', margin:'0 0 2px' }}>{value}</p>
                <p style={{ fontSize:'10px', color:'rgba(255,255,255,0.5)', margin:0, fontWeight:'500' }}>{label}</p>
              </div>
            ))}
          </div>

          {/* Avatars + rating */}
          <div style={{ display:'flex', alignItems:'center', gap:'14px' }}>
            <div style={{ display:'flex' }}>
              {['#C17B2A','#1E3A5F','#2A7A4A','#8B4B8B','#C44B4B'].map((c, i) => (
                <div key={i} style={{ width:'30px', height:'30px', borderRadius:'50%', background:c, border:'2px solid rgba(255,255,255,0.25)', marginLeft:i > 0 ? '-8px' : 0, display:'flex', alignItems:'center', justifyContent:'center', fontSize:'11px', fontWeight:'700', color:'#fff', zIndex:5 - i }}>
                  {['S','J','P','A','M'][i]}
                </div>
              ))}
            </div>
            <div>
              <p style={{ fontSize:'12px', fontWeight:'700', color:'#fff', margin:'0 0 1px' }}>
                ⭐ <span style={{ color:'#C17B2A' }}>4.9/5</span> average rating
              </p>
              <p style={{ fontSize:'11px', color:'rgba(255,255,255,0.45)', margin:0 }}>Trusted by 10,000+ homeowners</p>
            </div>
          </div>
        </div>
      </div>

      {/* ═══════════════════════════════════════════════
          RIGHT PANEL
      ═══════════════════════════════════════════════ */}
      <div style={{ flex:1, display:'flex', alignItems:'center', justifyContent:'center', padding:'40px 32px', overflowY:'auto', position:'relative', background:t.pageBg }}>

        {/* Theme toggle */}
        <button
          className="theme-toggle"
          onClick={() => setDark(d => !d)}
          title="Toggle dark/light mode"
          style={{
            position:'absolute', top:'20px', right:'20px',
            width:'40px', height:'40px', borderRadius:'50%',
            border:`1.5px solid ${t.border}`, background:t.cardBg,
            cursor:'pointer', fontSize:'17px',
            display:'flex', alignItems:'center', justifyContent:'center',
            boxShadow:t.shadow, zIndex:10,
          }}
        >
          {dark ? '☀️' : '🌙'}
        </button>

        <div style={{ width:'100%', maxWidth:'440px', animation:'fadeUp 0.5s ease both' }}>

          {/* ── Card ── */}
          <div style={{ background:t.cardBg, borderRadius:'20px', padding:'40px 40px', boxShadow:t.shadowCard, border:`1px solid ${t.border}` }}>

            {/* Form header */}
            {(title || subtitle) && (
              <div style={{ marginBottom:'28px' }}>
                {title && (
                  <h1 style={{ fontSize:'26px', fontWeight:'800', color:t.text, margin:'0 0 8px', letterSpacing:'-0.4px', lineHeight:1.2 }}>
                    {title}
                  </h1>
                )}
                {subtitle && (
                  <p style={{ fontSize:'14px', color:t.textSub, margin:0, lineHeight:1.55 }}>
                    {subtitle}
                  </p>
                )}
              </div>
            )}

            {children}
          </div>

          {/* Footer */}
          <p style={{ textAlign:'center', fontSize:'12px', color:t.textMuted, marginTop:'20px' }}>
            © {new Date().getFullYear()} PropMaintain · <Link to="/home" className="auth-link" style={{ fontSize:'12px' }}>Back to home</Link>
          </p>
        </div>
      </div>
    </div>
  );
};

export default AuthLayout;
